/**
 * Packed Knot Benchmarks
 *
 * Measures: encode, decode, random access, self-modification,
 * serialization, and comparison against JSON baseline.
 *
 * The thesis: two bits per crossing, shift and mask, zero parse.
 * Non-self-encoding always costs more (wrapper_costs theorem).
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import {
  FORK,
  FOLD,
  RACE,
  VENT,
  coil,
  release,
  getCrossing,
  setCrossing,
  composeKnots,
  hammingDistance,
  toBytes,
  fromBytes,
  edgeTypeToCrossing,
  type PackedKnot,
  type CrossingOp,
} from './packed-knot';
import type { GraphAST, ASTEdge } from '../betty/compiler';

// ─── Helpers ─────────────────────────────────────────────────────────

function makeEdge(type: string, src: string, tgt: string): ASTEdge {
  return { type, sourceIds: [src], targetIds: [tgt], properties: {} };
}

function makeLinearAST(n: number): GraphAST {
  const types = ['FORK', 'RACE', 'FOLD', 'VENT'];
  const nodes = new Map<
    string,
    { id: string; labels: string[]; properties: Record<string, string> }
  >();
  const edges: ASTEdge[] = [];
  for (let i = 0; i < n; i++) {
    const src = `n${i}`;
    const tgt = `n${i + 1}`;
    nodes.set(src, { id: src, labels: [src], properties: {} });
    nodes.set(tgt, { id: tgt, labels: [tgt], properties: {} });
    edges.push(makeEdge(types[i % 4], src, tgt));
  }
  return { nodes, edges };
}

function packFromOps(ops: CrossingOp[]): PackedKnot {
  const byteCount = Math.ceil(ops.length / 4);
  const crossings = new Uint8Array(byteCount);
  for (let i = 0; i < ops.length; i++) {
    crossings[i >> 2] |= ops[i] << (6 - 2 * (i & 3));
  }
  return {
    crossingCount: ops.length,
    crossings,
    nodeIds: ops.map((_, i) => `n${i}`),
  };
}

function bench(
  label: string,
  fn: () => void,
  warmup = 100,
  measured = 1000
): {
  label: string;
  opsPerSec: number;
  meanUs: number;
} {
  for (let i = 0; i < warmup; i++) fn();
  const start = performance.now();
  for (let i = 0; i < measured; i++) fn();
  const elapsed = performance.now() - start;
  const meanUs = (elapsed / measured) * 1000;
  return { label, opsPerSec: Math.round((measured / elapsed) * 1000), meanUs };
}

function reportBench(results: ReturnType<typeof bench>[]) {
  for (const r of results) {
    console.log(
      `  ${
        r.label
      }: ${r.opsPerSec.toLocaleString()} ops/sec (${r.meanUs.toFixed(2)} μs/op)`
    );
  }
}

// ─── Benchmark 1: Encode (coil) ──────────────────────────────────────

describe('Benchmark 1: Encode (coil)', () => {
  for (const size of [10, 100, 1000, 10000]) {
    it(`coil ${size} edges`, () => {
      const ast = makeLinearAST(size);
      const r = bench(`coil-${size}`, () => coil(ast), 50, 500);
      console.log(
        `  coil(${size}): ${r.opsPerSec.toLocaleString()} ops/sec (${r.meanUs.toFixed(
          1
        )} μs)`
      );
      expect(r.opsPerSec).toBeGreaterThan(0);
    });
  }
});

// ─── Benchmark 2: Decode (release) ───────────────────────────────────

describe('Benchmark 2: Decode (release)', () => {
  for (const size of [10, 100, 1000, 10000]) {
    it(`release ${size} crossings`, () => {
      const ops = Array.from({ length: size }, (_, i) => (i % 4) as CrossingOp);
      const knot = packFromOps(ops);
      const r = bench(
        `release-${size}`,
        () => {
          let count = 0;
          for (const _ of release(knot)) count++;
        },
        50,
        500
      );
      console.log(
        `  release(${size}): ${r.opsPerSec.toLocaleString()} ops/sec (${r.meanUs.toFixed(
          1
        )} μs)`
      );
      expect(r.opsPerSec).toBeGreaterThan(0);
    });
  }
});

// ─── Benchmark 3: Random Access ──────────────────────────────────────

describe('Benchmark 3: Random Access', () => {
  for (const size of [100, 1000, 10000]) {
    it(`getCrossing ${size} random reads`, () => {
      const ops = Array.from({ length: size }, (_, i) => (i % 4) as CrossingOp);
      const knot = packFromOps(ops);
      // Pre-generate random indices
      const indices = Array.from({ length: size }, () =>
        Math.floor(Math.random() * size)
      );
      const r = bench(
        `random-access-${size}`,
        () => {
          let sum = 0;
          for (const idx of indices) sum += getCrossing(knot, idx);
        },
        100,
        1000
      );
      console.log(
        `  random_access(${size}): ${r.opsPerSec.toLocaleString()} ops/sec (${r.meanUs.toFixed(
          1
        )} μs for ${size} reads)`
      );
      const perRead = (r.meanUs / size) * 1000;
      console.log(`    per-read: ${perRead.toFixed(1)} ns`);
      expect(r.opsPerSec).toBeGreaterThan(0);
    });
  }
});

// ─── Benchmark 4: Serialization Roundtrip ────────────────────────────

describe('Benchmark 4: Serialization', () => {
  for (const size of [100, 1000, 10000]) {
    it(`toBytes/fromBytes ${size} crossings`, () => {
      const ops = Array.from({ length: size }, (_, i) => (i % 4) as CrossingOp);
      const knot = packFromOps(ops);

      const rEncode = bench(`toBytes-${size}`, () => toBytes(knot), 50, 500);
      const bytes = toBytes(knot);
      const rDecode = bench(
        `fromBytes-${size}`,
        () => fromBytes(bytes),
        50,
        500
      );

      console.log(
        `  toBytes(${size}): ${rEncode.opsPerSec.toLocaleString()} ops/sec (${rEncode.meanUs.toFixed(
          1
        )} μs)`
      );
      console.log(
        `  fromBytes(${size}): ${rDecode.opsPerSec.toLocaleString()} ops/sec (${rDecode.meanUs.toFixed(
          1
        )} μs)`
      );
      expect(rEncode.opsPerSec).toBeGreaterThan(0);
    });
  }
});

// ─── Benchmark 5: Knot vs JSON ───────────────────────────────────────

describe('Benchmark 5: Knot vs JSON (wrapper_costs)', () => {
  for (const size of [100, 1000, 10000]) {
    it(`${size} operations: knot vs JSON encode+decode`, () => {
      const ops = Array.from({ length: size }, (_, i) => (i % 4) as CrossingOp);
      const knot = packFromOps(ops);
      const edgeNames = ops.map((op) => ['VENT', 'FOLD', 'RACE', 'FORK'][op]);

      // Knot roundtrip
      const rKnot = bench(
        `knot-roundtrip-${size}`,
        () => {
          const bytes = toBytes(knot);
          fromBytes(bytes);
        },
        50,
        500
      );

      // JSON roundtrip
      const rJson = bench(
        `json-roundtrip-${size}`,
        () => {
          const str = JSON.stringify(edgeNames);
          JSON.parse(str);
        },
        50,
        500
      );

      const speedup = rJson.meanUs / rKnot.meanUs;
      const knotBytes = toBytes(knot).length;
      const crossingBytes = Math.ceil(knot.crossingCount / 4);
      const jsonBytes = JSON.stringify(edgeNames).length;
      const crossingCompression = jsonBytes / crossingBytes;

      console.log(
        `  Knot: ${rKnot.opsPerSec.toLocaleString()} ops/sec (${rKnot.meanUs.toFixed(
          1
        )} μs)`
      );
      console.log(
        `  JSON: ${rJson.opsPerSec.toLocaleString()} ops/sec (${rJson.meanUs.toFixed(
          1
        )} μs)`
      );
      console.log(`  Speedup: ${speedup.toFixed(1)}x`);
      console.log(
        `  Wire: knot-total=${knotBytes}B, crossings-only=${crossingBytes}B, JSON=${jsonBytes}B`
      );
      console.log(
        `  Crossing compression: ${crossingCompression.toFixed(
          0
        )}x smaller than JSON`
      );
      // The crossing bits alone are always dramatically smaller than JSON.
      // The node ID table adds overhead (the wrapper that wrapper_costs warns about).
      expect(crossingCompression).toBeGreaterThan(1);
    });
  }
});

// ─── Benchmark 6: Compose ────────────────────────────────────────────

describe('Benchmark 6: Compose', () => {
  it('compose 1000 knots of 10 crossings each', () => {
    const small = packFromOps([
      FORK,
      RACE,
      FOLD,
      VENT,
      FORK,
      RACE,
      FOLD,
      VENT,
      FORK,
      FOLD,
    ]);
    const r = bench(
      'compose-1000x10',
      () => {
        let acc = packFromOps([]);
        for (let i = 0; i < 1000; i++) acc = composeKnots(acc, small);
      },
      5,
      20
    );
    console.log(
      `  compose(1000x10): ${r.opsPerSec.toLocaleString()} ops/sec (${r.meanUs.toFixed(
        0
      )} μs)`
    );
    expect(r.opsPerSec).toBeGreaterThan(0);
  });
});

// ─── Benchmark 7: Hamming Distance ──────────────────────────────────

describe('Benchmark 7: Hamming Distance', () => {
  for (const size of [100, 1000, 10000]) {
    it(`hammingDistance ${size} crossings`, () => {
      const a = packFromOps(
        Array.from({ length: size }, (_, i) => (i % 4) as CrossingOp)
      );
      const b = packFromOps(
        Array.from({ length: size }, (_, i) => ((i + 1) % 4) as CrossingOp)
      );
      const r = bench(
        `hamming-${size}`,
        () => hammingDistance(a, b),
        100,
        1000
      );
      console.log(
        `  hamming(${size}): ${r.opsPerSec.toLocaleString()} ops/sec (${r.meanUs.toFixed(
          1
        )} μs)`
      );
      expect(r.opsPerSec).toBeGreaterThan(0);
    });
  }
});

// ─── Benchmark 8: Self-Modification ──────────────────────────────────

describe('Benchmark 8: Self-Modification', () => {
  it('setCrossing 10000 mutations', () => {
    const knot = packFromOps(Array.from({ length: 10000 }, () => VENT));
    const r = bench(
      'set-10000',
      () => {
        for (let i = 0; i < 10000; i++)
          setCrossing(knot, i, (i % 4) as CrossingOp);
      },
      50,
      200
    );
    console.log(
      `  setCrossing(10000): ${r.opsPerSec.toLocaleString()} ops/sec (${r.meanUs.toFixed(
        0
      )} μs)`
    );
    const perMutation = (r.meanUs / 10000) * 1000;
    console.log(`    per-mutation: ${perMutation.toFixed(1)} ns`);
    expect(r.opsPerSec).toBeGreaterThan(0);
  });
});
